package org.apache.commons.csv;
import static org.apache.commons.csv.Token.Type.TOKEN;
import java.io.Closeable;
import java.io.File;
import java.io.FileReader;
import java.io.InputStreamReader;
import java.io.Reader;
import java.io.StringReader;
import java.util.ArrayList;
import java.util.Iterator;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import java.util.NoSuchElementException;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.net.URL;
import java.nio.charset.Charset;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVParserTest {

    private URL mockUrl;

    @BeforeEach
    void setUp() throws Exception {
        mockUrl = mock(URL.class);
        // Removed mockInputStream since not used directly here
        when(mockUrl.openStream()).thenReturn(null);
    }

    @Test
    void testParse_NullUrl() {
        Charset charset = Charset.forName("UTF-8");
        CSVFormat format = mock(CSVFormat.class);

        NullPointerException npe = assertThrows(NullPointerException.class, () -> {
            CSVParser.parse(null, charset, format);
        });
        assertEquals("url", npe.getMessage());
    }

    @Test
    void testParse_NullCharset() throws IOException {
        CSVFormat format = mock(CSVFormat.class);

        // Instead of mocking Assertions.notNull, just call parse with null charset and expect NPE
        NullPointerException npe = assertThrows(NullPointerException.class, () -> {
            CSVParser.parse(mockUrl, null, format);
        });
        assertEquals("charset", npe.getMessage());
    }

    @Test
    void testParse_NullFormat() {
        Charset charset = Charset.forName("UTF-8");

        NullPointerException npe = assertThrows(NullPointerException.class, () -> {
            CSVParser.parse(mockUrl, charset, null);
        });
        assertEquals("format", npe.getMessage());
    }

    @Test
    void testParse_ValidInputs() throws IOException {
        Charset charset = Charset.forName("UTF-8");
        CSVFormat format = mock(CSVFormat.class);

        // We must mock openStream to return a non-null InputStream to avoid NPE in CSVParser constructor
        when(mockUrl.openStream()).thenReturn(this.getClass().getResourceAsStream("/test.csv"));
        // If /test.csv does not exist, fallback to ByteArrayInputStream
        if (mockUrl.openStream() == null) {
            when(mockUrl.openStream()).thenReturn(new java.io.ByteArrayInputStream("a,b\n1,2".getBytes(charset)));
        }

        CSVParser parser = CSVParser.parse(mockUrl, charset, format);

        assertNotNull(parser);
    }
}
